# Embedded main module bytecode (compressed, base64-encoded)
_MAIN_PYC_B64 = """"""

def _load_main():
    raw = _zlib.decompress(_b64.b64decode(_MAIN_PYC_B64))
    return marshal.loads(raw)

def resource_path(name):
    base = Path(getattr(sys, '_MEIPASS', Path(__file__).resolve().parent))
    return base / name

