    def _purp(kw, keys):
        for k in keys:
            if k in kw and kw[k] in _BLUE_MAP:
                kw[k] = _BLUE_MAP[kw[k]]
    for _cls_name in ('Frame','Label','Button','Entry','Text','Canvas','LabelFrame',
                      'Listbox','Message','PanedWindow','Scrollbar'):
        _cls = getattr(_tk, _cls_name, None)
