    def localized_provider_guide(provider_name, language):
        lang = language if language in guide_text else 'en'
        try:
            base = original_provider_guide(provider_name, language) if original_provider_guide else {}
        except Exception:
            base = {}
        label = PROVIDER_LABELS.get(provider_name, provider_name)
        return {
            'title': base.get('title', label + ' Guide') if isinstance(base, dict) else label + ' Guide',
            'url': base.get('url', '') if isinstance(base, dict) else '',
            'text': guide_text[lang],
        }
    g['provider_guide'] = localized_provider_guide

    # ---- polished_card_init ----
    def polished_card_init(self, parent, app, result):
        Frame = tk.Frame
        Frame.__init__(self, parent, bg='#122030', highlightthickness=1, highlightbackground='#1f3448', bd=0)
        self.app = app
        self.result = result
        self.photo = None
        self.default_bg = '#122030'
        self.hover_bg = '#183149'
        self.selected_bg = '#1e4466'
        self.selected = False
        self._online_status = None
        try:
            configured = int(app.settings.get('card_width', card_width))
        except Exception:
            configured = card_width
        cw = max(404, min(configured, 520))
        iw = cw - 28
        try:
            image_h = max(150, min(int(app.settings.get('cover_height', cover_size[1])), 240))
        except Exception:
            image_h = cover_size[1]
        self.configure(width=cw, height=image_h + 270, cursor='hand2')
        self.grid_propagate(False)
        self.grid_columnconfigure(0, weight=1)
        self.image_label = tk.Label(self, bg='#0d1825', fg='#8fb8da', text='', relief=tk.FLAT)
        self.image_label.grid(row=0, column=0, sticky='n', padx=14, pady=(14, 10))
        self.title_label = tk.Label(self,
            text=result.get('name', ''),
            bg=self.default_bg, fg='#f7fafc',
            font=('Segoe UI Semibold', 11),
            anchor='w', justify='left', wraplength=iw)
        self.title_label.grid(row=1, column=0, sticky='ew', padx=14)
        self.meta_label = tk.Label(self,
            text='', bg=self.default_bg, fg='#8fb8da',
            font=('Segoe UI', 9),
            anchor='w', justify='left', wraplength=iw)
        self.meta_label.grid(row=2, column=0, sticky='ew', padx=14, pady=(6, 0))
        self.footer_label = tk.Label(self,
            text='', bg=self.default_bg, fg='#9cb2c8',
            font=('Segoe UI', 9),
            anchor='w', justify='left', wraplength=iw)
        self.footer_label.grid(row=3, column=0, sticky='ew', padx=14, pady=(4, 12))
        _no_dl = result.get('_no_download', False)
        if not _no_dl:
            _installed = result.get('installed', False)
            self._installed = _installed
            if _installed:
                _aid_launch = result.get('appid', '')
                self.btn_indir = AnimatedButton(self, app.tr('button.download'),
                    lambda: (__import__('subprocess').Popen(['cmd', '/c', 'start', f'steam://rungameid/{_aid_launch}'])), iw, 38,
                    '#2d4a3e', '#3d6b56', '#48bb78', '#f7fafc', ('Segoe UI Semibold', 10))
                self.btn_indir.grid(row=4, column=0, sticky='ew', padx=14, pady=(0, 8))
            else:
                _name = result.get('name', '') or ''
                self.btn_indir = AnimatedButton(self, app.tr('button.download'),
                    lambda n=_name, r=result: (_save_dl_name(n),
                        threading.Thread(target=lambda: app.indir_sonuclari(r), daemon=True).start()), iw, 38,
                    '#244363', '#315f8e', '#66c0f4', '#f7fafc', ('Segoe UI Semibold', 10))
                self.btn_indir.grid(row=4, column=0, sticky='ew', padx=14, pady=(0, 8))
        self._used_dot = None
        self.btn_steamdb = None
        try:
            if not hasattr(SteamApp, '_used_cache'):
                _bd2 = Path(__file__).resolve().parent
                _sv = app.settings.get('save_path', '') or app.settings.get('new_games_folder', '')
                _gd2 = Path(_sv) if _sv and Path(_sv).exists() else _bd2 / "1 New Games"
                _ip = _gd2 / "used" / "injected_games.ini"
                _tmp = {}
                if _ip.exists():
                    _c2 = _configparser.ConfigParser()
                    try: _c2.read(str(_ip), encoding='utf-8')
                    except: pass
                    if 'Games' in _c2:
                        for k in _c2['Games']:
                            nk = k.lower().strip()
                            for ch in ('.', '_', '-', '\u2122', '\u00ae', '(', ')', '[', ']', ':', ';'):
                                nk = nk.replace(ch, ' ')
                            while '  ' in nk: nk = nk.replace('  ', ' ')
                            _tmp[nk] = k
                SteamApp._used_cache = _tmp
            _raw = result.get('name', '') or ''
            _t = _raw.lower().strip()
            for ch in ('.', '_', '-', '\u2122', '\u00ae', '(', ')', '[', ']', ':', ';'):
                _t = _t.replace(ch, ' ')
            while '  ' in _t: _t = _t.replace('  ', ' ')
            _t = _t.strip()
            if _t and SteamApp._used_cache:
                for _k in SteamApp._used_cache:
                    if _t == _k or _k in _t or _t in _k:
                        _dot = tk.Label(self, text='\u25cf', fg='#e74c3c', bg=self.default_bg,
                                       font=('Segoe UI', 14))
                        _dot.place(relx=1.0, rely=0.0, anchor='ne', x=-6, y=6)
                        self._used_dot = _dot
                        break
        except: pass
        self.btn_onlinefix = AnimatedButton(self, app.tr('button.onlinefix'),
            lambda: app.open_onlinefix(result), iw, 36,
            '#2d4a3e', '#3d6b56', '#66c0f4', '#f7fafc', ('Segoe UI Semibold', 9))
        self.btn_onlinefix.grid(row=5, column=0, sticky='ew', padx=14, pady=(0, 8))

        for widget in (self.image_label, self.title_label, self.meta_label, self.footer_label):
            widget.bind('<Enter>', self._on_enter)
            widget.bind('<Leave>', self._on_leave)
            widget.bind('<Button-1>', self._on_select)
            widget.bind('<Double-1>', self._on_open)
        self.refresh_texts()
        self._check_online_status()
        # Trigger image loading from the internet
        _aid = str(result.get('appid', ''))
        if _aid:
            self.app.image_watchers.setdefault(_aid, []).append(self)
            if _aid in self.app.image_cache:
                try:
                    self.set_image(self.app.image_cache[_aid])
                except Exception:
                    pass
            else:
                threading.Thread(target=self.app._image_worker,
                                 args=(self.result,), daemon=True).start()

    # ---- polished_reflow_cards ----
    def polished_reflow_cards(self):
        if not self.cards:
            return
        width = max(self.results_canvas.winfo_width(), 820)
        try:
            cw = max(404, min(int(self.settings.get('card_width', card_width)), 520))
        except Exception:
            cw = card_width
        columns = max(1, (width + 28) // (cw + 28))
        for idx, card in enumerate(self.cards):
            row = idx // columns
            col = idx % columns
            card.grid(row=row, column=col, padx=14, pady=14, sticky='nsew')
        for col in range(columns):
            self.cards_frame.grid_columnconfigure(col, weight=1, uniform='card_col')
        self.results_canvas.configure(scrollregion=self.results_canvas.bbox('all'))

    # ---- placeholder_image ----
    def placeholder_image(self, title):
        canvas = Image.new('RGB', cover_size, '#16273a')
        draw = ImageDraw.Draw(canvas)
        draw.rectangle([(0, 0), (cover_size[0], cover_size[1])], fill='#0f1b2a')
        draw.rectangle([(0, 0), (cover_size[0], 62)], fill='#19324a')
        initials = ''.join(word[0] for word in clean_title(title).split()[:2]).upper() or 'ST'
        draw.ellipse((24, 78, 114, 168), fill='#66c0f4')
        draw.text((49, 104), initials, fill='#07111c')
        draw.text((140, 90), clean_title(title)[:32], fill='#f7fafc')
        draw.text((140, 118), self.tr('placeholder.header_failed'), fill='#8ca5be')
        return canvas

    # ---- image_worker ----
    _img_ua = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'

    def image_worker(self, result):
        image_url = result.get('image_url')
        image = None
        try:
            image_h = max(150, min(int(self.settings.get('cover_height', cover_size[1])), 240))
        except Exception:
            image_h = cover_size[1]
        size = (cover_size[0], image_h)
        if image_url:
            try:
                headers = {'User-Agent': _img_ua}
                response = g['session'].get(image_url, timeout=20, headers=headers)
                response.raise_for_status()
                pil_image = Image.open(g['io'].BytesIO(response.content)).convert('RGB')
                contained = ImageOps.contain(pil_image, size, method=Image.Resampling.LANCZOS)
                image = Image.new('RGB', size, '#0d1825')
                image.paste(contained, ((size[0] - contained.width) // 2, (size[1] - contained.height) // 2))
            except Exception:
                pass
        if image is None:
            image = ImageOps.contain(self.placeholder_image(result['name']), size, method=Image.Resampling.LANCZOS)
        self.ui(self._finalize_image, result['appid'], image)

    # ---- finalize_image ----
    def finalize_image(self, appid, image):
        photo = ImageTk.PhotoImage(image)
        self.image_cache[appid] = photo
        for card in self.image_watchers.pop(appid, []):
            card.set_image(photo)

    # ---- play_notification ----
    def play_notification():
        sound = resource_path('bildirim sesi.mp3')
        if not sound.exists():
            return
        alias = 'steamtools_notice'
        winmm = ctypes.windll.winmm
        winmm.mciSendStringW('stop ' + alias, None, 0, None)
        winmm.mciSendStringW('close ' + alias, None, 0, None)
        winmm.mciSendStringW('open "' + str(sound) + '" type mpegvideo alias ' + alias, None, 0, None)
        winmm.mciSendStringW('play ' + alias + ' from 0', None, 0, None)

    # ---- set_status_key_with_sound ----
    original_set_status_key = SteamApp.set_status_key

    def set_status_key_with_sound(self, key, *args, **kwargs):
        original_set_status_key(self, key, *list(args), **dict(kwargs))
        if key in frozenset({'status.download_failed', 'status.download_complete',
                              'status.unlock_done', 'status.unlock_failed'}):
            play_notification()

    # ---- localized_rate_text ----
    def localized_rate_text(self, provider_name):
        info = self.provider_manager.rate_info.get(provider_name)
        if not info:
            return self.tr('settings.not_queried')
        if info.get('status') == 'yerel':
            return self.tr('settings.unlimited_local')
        if info.get('status') == 'yok':
            return self.tr('settings.no_limit_info')
        if info.get('status') == 'hata':
            return self.tr('settings.rate_error')
        if provider_name == 'groq':
            return self.tr('settings.requests') + ': ' + str(info.get('requests', '?')) + ' | Token: ' + str(info.get('tokens', '?'))
        if provider_name == 'openrouter':
            return self.tr('settings.remaining') + ': ' + str(info.get('remaining', '?'))
        return self.tr('settings.not_queried')

    # ---- Apply patches ----
    old_init = GameCard.__init__
    GameCard.__init__ = polished_card_init
    SteamApp.reflow_cards = polished_reflow_cards
    SteamApp.placeholder_image = placeholder_image
    SteamApp._image_worker = image_worker
    SteamApp._finalize_image = finalize_image
    SteamApp.set_status_key = set_status_key_with_sound
    # Patch refresh_texts, set_busy, _on_open to skip removed btn_steamdb
    _orig_refresh = GameCard.refresh_texts
    def _patched_refresh(self):
        source_key = self.result.get('source_key')
        if source_key:
            source_text = self.app.tr(source_key)
        else:
            source_text = self.result.get('source', '')
        footer_key = 'footer.free' if self.result.get('is_free') else 'footer.verified'
        self.meta_label.configure(text=f"App ID: {str(self.result.get('appid', ''))}  |  {source_text}")
        self.footer_label.configure(text=self.app.tr(footer_key))
        self.btn_indir.set_text(self.app.tr('button.download'))
        self.btn_onlinefix.set_text(self.app.tr('button.onlinefix'))
        self.set_busy(False)
    GameCard.refresh_texts = _patched_refresh
    _orig_set_busy = GameCard.set_busy
    def _patched_set_busy(self, value):
        global_busy = bool(getattr(self.app, 'busy', False))
        self.btn_indir.set_enabled(not global_busy)
        self.btn_onlinefix.set_enabled(not global_busy)
    GameCard.set_busy = _patched_set_busy
    _orig_on_open = GameCard._on_open
    def _patched_on_open(self, event):
        self.app.open_onlinefix(self.result)
    GameCard._on_open = _patched_on_open

    # ---- Status Indicator Helper ----
    def _set_indicator(self, text, state):
        try:
            if not hasattr(self, '_indicator_history'):
                self._indicator_history = []
            ts = _time.strftime('%H:%M:%S')
            self._indicator_history.append((ts, text, state))
            if len(self._indicator_history) > 50:
                self._indicator_history.pop(0)
            if hasattr(self, 'set_status'):
                self.set_status(text, state)
            else:
                colors = {'idle':'#708090','working':'#f6ad55','online':'#48bb78','offline':'#f56565'}
                if hasattr(self, 'status_dot') and hasattr(self, 'status_oval'):
                    self.status_dot.itemconfig(self.status_oval, fill=colors.get(state, colors['idle']))
                if hasattr(self, 'status_var'):
                    self.status_var.set(text)
                # Update tooltip/detail
                if hasattr(self, 'status_lbl') and self.status_lbl.winfo_exists():
                    last_dl = [h for h in reversed(self._indicator_history) if 'downloaded' in h[1].lower() or 'unlock' in h[1].lower() or 'inject' in h[1].lower()]
                    detail = f'Son: {text}'
                    if last_dl:
                        detail += f'\n{last_dl[0][0]} {last_dl[0][1]}'
                    self.status_lbl.config(text=detail[:60])
        except Exception:
            pass

    SteamApp._set_indicator = _set_indicator

    # ---- Headless PowerShell Runner ----
    import os as _os
    import shutil as _shutil
    import subprocess as _subprocess
    import tempfile as _tempfile
    import zipfile as _zipfile
    import configparser as _configparser
    import tkinter.messagebox as _messagebox
    import time as _time
    _batch_threading = threading

    # ---- Sound effects (disabled) ----
    def _play_sound(kind):
        pass

    def _run_headless_powershell(self, cmd, label, status_light=None):
        def _task():
            try:
                self.log(f"[{label}] başlatılıyor...")
                self._set_indicator(f"{label} {_tr(self, 'indicator.working')}", 'working')
                if status_light is not None:
                    try: status_light.config(fg='#f6ad55')
                    except: pass
                si = _subprocess.STARTUPINFO()
                si.dwFlags |= _subprocess.STARTF_USESHOWWINDOW
                result = _subprocess.run(
                    ["powershell", "-Command", cmd],
                    capture_output=True, text=True, timeout=300,
                    startupinfo=si, creationflags=0x08000000
                )
                if result.returncode == 0:
                    msg = f"{label} başarıyla tamamlandı."
                    self.log(f"[{label}] {msg}")
                    self._set_indicator(msg, 'online')
                    _play_sound('done')
                    if status_light is not None:
                        try: status_light.config(fg='#48bb78')
                        except: pass
                    # Post-install: move ltsteamplugin-main up one level
                    if 'luatools' in label.lower():
                        try:
                            _plugins = Path("C:\\Program Files (x86)\\Steam\\millennium\\plugins")
                            _luatools_dir = _plugins / "luatools"
                            if _luatools_dir.exists():
                                _subs = [d for d in _luatools_dir.iterdir() if d.is_dir()]
                                if _subs:
                                    _src = _subs[0]
                                    _dst = _plugins / _src.name
                                    if not _dst.exists():
                                        _shutil.move(str(_src), str(_dst))
                                        self.log(f"{_src.name} başarıyla plugins/ klasörüne taşındı.")
                        except Exception as e:
                            self.log(f"luatools klasör taşıma hatası: {e}")
                else:
                    err = result.stderr.strip()[:200] or "Bilinmeyen hata"
                    self.log(f"[{label}] HATA: {err}")
                    self._set_indicator(f"{label} {_tr(self, 'indicator.fail')}", 'offline')
                    _play_sound('error')
                    if status_light is not None:
                        try: status_light.config(fg='#f56565')
                        except: pass
            except _subprocess.TimeoutExpired:
                self.log(f"[{label}] zaman aşımı!")
                self._set_indicator(f"{label} {_tr(self, 'indicator.timeout')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
            except Exception as e:
                self.log(f"[{label}] HATA: {e}")
                self._set_indicator(f"{label} {_tr(self, 'indicator.err')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
        _batch_threading.Thread(target=_task, daemon=True).start()
        _play_sound('start')

    SteamApp._run_headless_powershell = _run_headless_powershell

    # ---- Batch Inject All ----
    def batch_inject_all(self):
        base_dir = Path(__file__).resolve().parent
        saved = self.settings.get('save_path', '') or self.settings.get('new_games_folder', '')
        if saved and Path(saved).exists():
            games_dir = Path(saved)
        else:
            games_dir = base_dir / "1 New Games"
        if not games_dir.exists():
            try:
                games_dir.mkdir(parents=True, exist_ok=True)
                self.log(f"[1 New Games] klasörü oluşturuldu: {games_dir}")
            except Exception as e:
                self.log(f"[1 New Games] klasörü oluşturulamadı: {e}")
                _messagebox.showerror(_tr(self, 'inject.err_title'), f"{_tr(self, 'inject.err_create')}\n{e}")
                return
        self.settings['new_games_folder'] = str(games_dir.resolve())
        g['save_settings'](self.settings)
        self.log(f"Taranan klasör: {games_dir}")
        self._set_indicator(_tr(self, 'indicator.scanning'), 'working')
        zips = sorted(games_dir.glob("*.zip"))
        if not zips:
            self.log(f"[{games_dir.name}] içinde .zip dosyası bulunamadı.")
            self._set_indicator(_tr(self, 'indicator.no_zips'), 'idle')
            _messagebox.showinfo(_tr(self, 'inject.info_title'), _tr(self, 'inject.no_zips_msg'))
            return
        # Show selection overlay inside main window
        _parent = getattr(self, 'results_canvas', None) or getattr(self, 'cards_frame', None) or self.root
        _sel_vars = {}
        _ov = tk.Frame(self.root, bg='#08080e', highlightthickness=1, highlightbackground='#1a1a30')
        _ov.place(x=0, y=0, relwidth=1, relheight=1, anchor='nw')
        _ov.lift()
        _top = tk.Frame(_ov, bg='#08080e')
        _top.pack(fill=tk.X, padx=16, pady=(14, 6))
        tk.Label(_top, text=_tr(self, 'inject.select_title'), font=('Bahnschrift SemiBold', 18),
                 fg='#e0e0f0', bg='#08080e').pack(side=tk.LEFT)
        _sel_all = tk.BooleanVar(value=True)
        def _toggle_all():
            v = _sel_all.get()
            for var in _sel_vars.values(): var.set(v)
        tk.Checkbutton(_top, text=_tr(self, 'inject.select_all'), variable=_sel_all,
                       command=_toggle_all, bg='#08080e', activebackground='#12122a',
                       selectcolor='#7c6fff', fg='#c0c0e0', font=('Segoe UI', 10)).pack(side=tk.RIGHT, padx=4)
        _sep = tk.Frame(_ov, bg='#1a1a30', height=1)
        _sep.pack(fill=tk.X, padx=16)
        _cf = tk.Frame(_ov, bg='#0a0a16')
        _cf.pack(fill=tk.BOTH, expand=True, padx=16, pady=(8, 10))
        _canv = tk.Canvas(_cf, bg='#0a0a16', highlightthickness=0)
        _scr = ttk.Scrollbar(_cf, orient=tk.VERTICAL, command=_canv.yview)
        _inner = tk.Frame(_canv, bg='#0a0a16')
        _inner.bind('<Configure>', lambda e: _canv.configure(scrollregion=_canv.bbox('all')))
        _canv.create_window((0, 0), window=_inner, anchor='nw')
        _canv.configure(yscrollcommand=_scr.set)
        _canv.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        _scr.pack(side=tk.RIGHT, fill=tk.Y)
        def _mw(e): _canv.yview('scroll', -e.delta//30, 'units')
        _canv.bind('<MouseWheel>', _mw)
        for i, zp in enumerate(zips):
            var = tk.BooleanVar(value=True)
            _sel_vars[zp] = var
            nm = zp.stem.replace('_', ' ').replace('-', ' ').strip()
            nm = ' '.join(w.capitalize() for w in nm.split())
            bg = '#0c0c20' if i % 2 == 0 else '#0a0a16'
            row = tk.Frame(_inner, bg=bg)
            row.pack(fill=tk.X, padx=6, pady=1)
            tk.Checkbutton(row, variable=var, bg=bg, activebackground='#14142a', selectcolor='#7c6fff',
                           fg='#d0d0e8', font=('Segoe UI', 10)).pack(side=tk.LEFT)
            tk.Label(row, text=nm, bg=bg, fg='#d0d0e8', font=('Segoe UI', 10), anchor='w').pack(side=tk.LEFT, fill=tk.X, expand=True)
            tk.Label(row, text=zp.name, bg=bg, fg='#686880', font=('Segoe UI', 8), anchor='e').pack(side=tk.RIGHT, padx=4)
        _btnf = tk.Frame(_ov, bg='#08080e')
        _btnf.pack(fill=tk.X, padx=16, pady=(0, 14))
        _ok = [False]
        def _confirm():
            _ok[0] = True; _ov.destroy()
        def _cancel():
            _ov.destroy()
        AB = g.get('AnimatedButton', AnimatedButton)
        AB(_btnf, _tr(self, 'inject.select_inject'), _confirm, 140, 34,
           '#1c1c3a', '#2a2a5a', '#7c6fff', '#e0e0f0',
           ('Segoe UI Semibold', 10)).pack(side=tk.RIGHT, padx=(8, 0))
        AB(_btnf, _tr(self, 'button.close'), _cancel, 110, 34,
           '#14142a', '#1e1e42', '#7c6fff', '#c0c0e0',
           ('Segoe UI', 9)).pack(side=tk.RIGHT)
        self.root.wait_window(_ov)
        if not _ok[0]: return
        chosen = [zp for zp, var in _sel_vars.items() if var.get()]
        if not chosen:
            _messagebox.showinfo(_tr(self, 'inject.info_title'), _tr(self, 'inject.no_zips_msg'))
            return
        self.log(f"Seçilen: {len(chosen)}/{len(zips)} zip")
        self._set_indicator(f"{len(chosen)} zip seçildi, inject başlıyor...", 'working')
        depot_dir = Path("C:\\Program Files (x86)\\Steam\\config\\depotcache")
        stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
        depot_dir.mkdir(parents=True, exist_ok=True); stplug_dir.mkdir(parents=True, exist_ok=True)
        used_dir = games_dir / "used"
        used_dir.mkdir(parents=True, exist_ok=True)
        ini_path = used_dir / "injected_games.ini"
        _config = _configparser.ConfigParser()
        if ini_path.exists():
            try: _config.read(str(ini_path), encoding='utf-8')
            except: pass
        if 'Games' not in _config: _config['Games'] = {}
        done = 0
        for zip_path in chosen:
            try:
                self.log(f"[{zip_path.name}] işleniyor...")
                with _zipfile.ZipFile(zip_path, 'r') as zf:
                    entries = [info for info in zf.infolist() if not info.is_dir()]
                    self.log(f"  -> {len(entries)} dosya bulundu")
                    for info in entries:
                        target = depot_dir if info.filename.endswith('.manifest') else stplug_dir
                        flat_name = Path(info.filename).name
                        tag = 'manifest' if info.filename.endswith('.manifest') else 'lua/st'
                        self.log(f"     [{tag}] {flat_name} -> {target.name}/")
                        (target / flat_name).write_bytes(zf.read(info))
                game_name = zip_path.stem.replace('_', ' ').replace('-', ' ').strip()
                game_name = ' '.join(w.capitalize() for w in game_name.split())
                ts = _time.strftime('%Y-%m-%d %H:%M')
                _config['Games'][game_name] = ts
                dest = used_dir / zip_path.name
                _shutil.move(str(zip_path), str(dest))
                self.log(f"[{zip_path.name}] -> used/ taşındı, {game_name} kaydedildi"); done += 1
            except Exception as e:
                self.log(f"[{zip_path.name}] HATA: {e}")
        try:
            with open(str(ini_path), 'w', encoding='utf-8') as f:
                _config.write(f)
        except: pass
        self.log(f"{done}/{len(zips)} inject edildi.")
        self._set_indicator(_tr(self, 'indicator.done'), 'online' if done > 0 else 'offline')
        if done > 0: _play_sound('done')
        else: _play_sound('error')
        if done > 0 and _messagebox.askyesno(_tr(self, 'inject.done_title'), _tr(self, 'inject.ask_restart').format(count=done)):
            g['save_settings'](self.settings)
            self.log("Steam kapatılıyor...")
            self._set_indicator(_tr(self, 'indicator.steam_stop'), 'working')
            _subprocess.run(["taskkill", "/f", "/im", "steam.exe"], capture_output=True)
            _time.sleep(5)
            self.log("Steam başlatılıyor...")
            self._set_indicator(_tr(self, 'indicator.steam_start'), 'working')
            _subprocess.Popen(["C:\\Program Files (x86)\\Steam\\steam.exe"])
            self.log("Steam yeniden başlatıldı.")
