    def _th_hex(r, g, b):
        return f"#{max(0,min(255,int(r))):02x}{max(0,min(255,int(g))):02x}{max(0,min(255,int(b))):02x}"
    def _th_lerp(a, b, t):
        return a + (b - a) * max(0, min(1, t))
    def _th_lerpc(c1, c2, t):
        def p(c): return tuple(int(c[i:i+2], 16) for i in (1,3,5))
        r1,g1,b1 = p(c1); r2,g2,b2 = p(c2)
        t = max(0, min(1, t))
        return _th_hex(_th_lerp(r1,r2,t), _th_lerp(g1,g2,t), _th_lerp(b1,b2,t))
